var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"으아아아!!!!","JPN":"うああああ！！！！","ENG":"ERRAGHH!!!","TWN":"啊啊啊啊！！！"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"방금 게 마지막이었어, 언니.","JPN":"今のが最後だったよ、姉さん。","ENG":"That was the last one, Nicole.","TWN":"剛剛那一下就是最後了，姐姐。"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"움직이지도 않는 호박한테 계속 갈겨봐야 의미 없다고.","JPN":"動かないカボチャを撃ち続けたところで意味ないって。","ENG":"There's no point unloading on a pumpkin that's not even moving.","TWN":"對著一個不會動的南瓜亂射，也沒有意義。"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"하아… 하…","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"哈啊……哈……"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"본체는 우리가 싸우는 틈에 도망친 것 같아.","JPN":"本体は私たちが戦ってる間に逃げたみたいだね。","ENG":"The real one probably slipped away while we were fighting.","TWN":"看來本體趁我們交戰時逃跑了。"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"도시관리국의 모니터링 팀에 추적이라도 부탁해볼까?","JPN":"都市管理局のモニタリングチームに追跡を頼んでみる？","ENG":"Should we ask the City Management's monitoring team to track it?","TWN":"要不要請城市管理局的監控小組協助追蹤？"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"아뇨. 악마가 아니어도 그분들은 다른 문제로 충분히 바쁘실 테니까요.","JPN":"いいえ、あの方たちは悪魔以外のことだけでも十分忙しいでしょうから。","ENG":"No. Even if they're not devils, they must already be busy enough with other problems.","TWN":"不用了。就算不是魔鬼，他們也因為其他問題已經夠忙了。"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"우선 시민들부터 안전한 장소로 모시죠.","JPN":"まずは市民を安全な場所に案内しましょう。","ENG":"Let's get the civilians to a safe place first.","TWN":"先把市民們帶到安全的地方吧。"},"stage":{"bg":"DOCK_NIGHT","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"잡혀 있던 사람들 전부 돌려보냈어.","JPN":"捕まっていた市民を全部帰したよ。","ENG":"Everyone who was being held has been sent back.","TWN":"被抓的人已經全部送回去了。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"딱 실종자 수만큼 있었다네.","JPN":"ちょうど失踪者の数と一致したってさ。","ENG":"Exactly the same number as the missing persons.","TWN":"數量正好和失蹤人口一樣。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…다행이네요.","JPN":"……よかったです。","ENG":"...That's a relief.","TWN":"……太好了。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"고생하셨어요.","JPN":"お疲れ様でした。","ENG":"You did great.","TWN":"辛苦了。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"꿀인삼차 마실래? 편의점에서 산 건데.","JPN":"蜂蜜高麗人参ドリンクでも飲む？　コンビニで買ってきたけど。","ENG":"Want some honey ginseng tea? I picked it up at a convenience store.","TWN":"要喝蜂蜜人蔘茶嗎？我在便利商店買的。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"꿀… 인삼… 차요?","JPN":"蜂蜜……高麗人参……ドリンクですか？","ENG":"Honey... ginseng... tea?","TWN":"蜂蜜……人蔘……茶？"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"싫음 말고.","JPN":"嫌ならいいけど。","ENG":"If you don't want it, never mind.","TWN":"不喝就算了。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"아뇨. 주세요.","JPN":"いいえ、いただきます。","ENG":"No. I'll take it.","TWN":"不，請給我。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"신경 써줘서 고마워요. 잘 마실게요.","JPN":"お気遣いありがとうございます。","ENG":"Thank you for thinking of me. I'll enjoy it.","TWN":"謝謝你這麼關心我，我會好好享用的。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"미안해요.","JPN":"ごめんなさい。","ENG":"I'm sorry.","TWN":"對不起。"},"stage":{"bg":"OMEN_G1_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"카운터도 아닌데, 혼자 멋대로 행동하고 다녀서.","JPN":"カウンターでもないくせに勝手に行動して。","ENG":"I'm not even a Counter, yet I went around acting on my own.","TWN":"我明明不是制裁者，卻擅自一個人行動。"},"stage":{"bg":"OMEN_G1_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그런 건 이제 됐어.","JPN":"それはもういいよ。","ENG":"That's water under the bridge now.","TWN":"那種事就算了吧。"},"stage":{"bg":"OMEN_G1_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"내가 걱정하지 않아도 될 정도로 언니가 강하다는 건, 이미 충분히 확인했으니까.","JPN":"私が心配する必要がないほど姉さんが強いってことは、十分確認したから。","ENG":"I've already seen enough to know you're strong enough that I don't need to worry.","TWN":"我已經充分確認了，你強到不需要我擔心。"},"stage":{"bg":"OMEN_G1_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그럼…","JPN":"では……","ENG":"Then...","TWN":"那麼……"},"stage":{"bg":"OMEN_G1_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"제가 마왕도 꺾을 수 있을까요?","JPN":"私でも魔王に勝てるでしょうか？","ENG":"Do you think I could defeat a Demon Lord?","TWN":"我能夠打倒魔王嗎？"},"stage":{"bg":"OMEN_G1_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…나도 몰라.","JPN":"……さあね。","ENG":"...I don't know.","TWN":"……我也不知道。"},"stage":{"bg":"OMEN_G1_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"내가 알던 제일 센 사람조차, 마왕의 상대가 되지 못했다는 사실만 알고 있을 뿐이지.","JPN":"私の知っている中で一番強かった人も、魔王の相手には成り得かった……それだけは確か。","ENG":"All I know is that even the strongest person I knew couldn't stand up to a Demon Lord.","TWN":"我只知道，連我認識的最強的人，都不是魔王的對手。"},"stage":{"bg":"OMEN_G1_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"역시, 저 혼자의 힘만으론 안되겠네요.","JPN":"やっぱり、私一人の力では無理ですよね。","ENG":"I guess I can't do it on my own after all.","TWN":"果然，光靠我一個人的力量不夠呢。"},"stage":{"bg":"OMEN_G1_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"관리국이라면… 그 마왕으로부터 사람들을 지켜낼 수 있겠죠?","JPN":"管理局なら……あの魔王から人々を守り抜けるでしょうか。","ENG":"If it's the Administration... they can protect people from a Demon Lord, right?","TWN":"如果是管理局……應該保護大家免於魔王傷害吧？"},"stage":{"bg":"OMEN_G1_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OMEN_G1_01","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};